import React from 'react';
import styles from './PlayerTable.module.css'; // Reuses your existing table design stylesheet

export default function TeamTable({
  data,
  total,
  page,
  pageSize,
  loading,
  sortBy,
  sortDir,
  onSort,
  onPage,
}) {
  const totalPages = Math.ceil(total / pageSize) || 1;

  const renderSortIcon = (key) => {
    if (sortBy !== key) return <span className={styles.sortNone}>↕</span>;
    return sortDir === 'asc' ? '↑' : '↓';
  };

  return (
    <div className={styles.tableWrapper}>
      <table className={styles.table}>
        <thead>
          <tr>
            <th onClick={() => onSort('team_name')} className={styles.sortable}>
              Team Name {renderSortIcon('team_name')}
            </th>
            <th onClick={() => onSort('league')} className={styles.sortable}>
              League {renderSortIcon('league')}
            </th>
            <th onClick={() => onSort('coach')} className={styles.sortable}>
              Head Coach {renderSortIcon('coach')}
            </th>
            <th>Top Athletes</th>
            <th onClick={() => onSort('roster_count')} className={styles.sortable}>
              Roster Count {renderSortIcon('roster_count')}
            </th>
          </tr>
        </thead>
        <tbody>
          {loading ? (
            <tr><td colSpan={5} className={styles.center}>Loading roster details...</td></tr>
          ) : data.length === 0 ? (
            <tr><td colSpan={5} className={styles.center}>No teams found matching search inputs.</td></tr>
          ) : (
            data.map((team) => (
              <tr key={team.id || team.team_name}>
                <td className={styles.bold}>{team.team_name}</td>
                <td><span className={styles.badge}>{team.league}</span></td>
                <td>{team.coach || '—'}</td>
                
                {/* Fixed: Maps clean inline layout formatting safely for your nested roster sets */}
                <td className={styles.subtext}>
                  {Array.isArray(team.athletes) ? team.athletes.join(', ') : team.athletes || '—'}
                </td>
                
                <td className={styles.bold}>{team.roster_count ?? 0}</td>
              </tr>
            ))
          )}
        </tbody>
      </table>

      {/* Pagination Footer Controls */}
      <div className={styles.pagination}>
        <span className={styles.pageInfo}>
          Showing {page * pageSize + 1} - {Math.min((page + 1) * pageSize, total)} of {total}
        </span>
        <div className={styles.pageButtons}>
          <button 
            disabled={page === 0 || loading} 
            onClick={() => onPage(page - 1)}
            className={styles.pageBtn}
          >
            Prev
          </button>
          <span className={styles.activePage}>{page + 1} / {totalPages}</span>
          <button 
            disabled={page >= totalPages - 1 || loading} 
            onClick={() => onPage(page + 1)}
            className={styles.pageBtn}
          >
            Next
          </button>
        </div>
      </div>
    </div>
  );
}
